local Config = {}

LevelConfig = {}

function LevelConfig:init(config)
    for _, vConfig in pairs(config) do
        local group = Config[tonumber(vConfig.groupId)]
        if not group then
            group = {}
            Config[tonumber(vConfig.groupId)] = group
        end
        table.insert(group, {
            expLimit = tonumber(vConfig.expLimit),
            currentLevel = tonumber(vConfig.currentLevel),
            upgradeAdditionIds = StringUtil.split(vConfig.upgradeAdditionIds, "#")
        })
    end
    for _, group in pairs(Config) do
        table.sort(group, function(a, b)
            return a.currentLevel < b.currentLevel
        end)
    end
end

function LevelConfig:getConfigByGroupId(id)
    return Config[id]
end

